INSERT INTO `prompt_rules` (`id`, `name`, `description`, `content`, `enabled`, `createdAt`, `updatedAt`) VALUES ('5d4cdf58-b62e-404b-8654-3d9c14f17d4b', '签单查询', '定义签单、业绩相关的查询', '1、当需要查询签单业绩的时候，如果没有特殊指定，默认查询20合同的签单数据\n2、查询签单情况的时候，需要同时查询20合同个数、20合同总金额\n3、查询签单情况的时候，默认按照设计师分组，如果指定了设计部门，或者其他部门，则按照用户规则统计', 1, '2026-03-21 06:52:53.308', '2026-03-21 06:52:53.308');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('122a8912-a7c3-4ec1-a26d-62438b468e11', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年的客户', 'SELECT *\nFROM Crm_IntentCustomer\nWHERE isFormDead = 0\n  AND CreateDate >= \'2026-01-01\'\n  AND CreateDate < \'2027-01-01\'', '客户信息', 1, '2026-03-20 16:01:35.286');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('2422f121-ee8f-4cf1-8d43-aeb4accf275c', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    ci.DesignerDeptName AS 设计部门,\n    COUNT(tk.IntentCustomerId) AS 合同个数,\n    ISNULL(SUM(tk.[20htje]), 0) AS 合同总金额,\n    CAST(ROUND(COUNT(tk.IntentCustomerId) * 100.0 / COUNT(*), 2) AS NUMERIC(10,2)) AS 签单率\nFROM Crm_IntentCustomer ci\nLEFT JOIN Form_Custom_TK0022 tk ON ci.IntentCustomerId = tk.IntentCustomerId\n    AND YEAR(tk.[20htrq]) = 2025\nWHERE ci.DesignerDeptName IS NOT NULL\nGROUP BY ci.DesignerDeptName\nORDER BY 签单率 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 02:45:18.489');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('255d2c0e-da32-4ce9-9c81-f1b74b131c84', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'WITH TotalCustomer AS (\n    SELECT \n        [DesignerDeptName] AS [设计部门],\n        COUNT(*) AS [总客户数]\n    FROM Crm_IntentCustomer WITH(NOLOCK)\n    WHERE [IsFormDead] = 0 \n        AND YEAR([CreateDate]) = 2025\n        AND [DesignerDeptName] IS NOT NULL\n    GROUP BY [DesignerDeptName]\n),\nSignedCustomer AS (\n    SELECT \n        c.[DesignerDeptName] AS [设计部门],\n        COUNT(DISTINCT c.[IntentCustomerId]) AS [签单客户数]\n    FROM Crm_IntentCustomer c WITH(NOLOCK)\n    INNER JOIN Form_Custom_TK0022 tk WITH(NOLOCK) ON c.[IntentCustomerId] = tk.[IntentCustomerId]\n    WHERE c.[IsFormDead] = 0 \n        AND YEAR(tk.[CreateDate]) = 2025\n        AND c.[DesignerDeptName] IS NOT NULL\n    GROUP BY c.[DesignerDeptName]\n)\nSELECT \n    tc.[设计部门],\n    tc.[总客户数],\n    ISNULL(sc.[签单客户数], 0) AS [签单客户数],\n    CASE \n        WHEN tc.[总客户数] > 0 \n        THEN CAST(CAST(ISNULL(sc.[签单客户数], 0) * 100.0 / tc.[总客户数] AS DECIMAL(10,2)) AS NVARCHAR) + \'%\'\n        ELSE \'0%\'\n    END AS [签单率]\nFROM TotalCustomer tc\nLEFT JOIN SignedCustomer sc ON tc.[设计部门] = sc.[设计部门]\nORDER BY ISNULL(sc.[签单客户数], 0) * 1.0 / tc.[总客户数] DESC', '客户信息,20合同', 1, '2026-03-21 07:00:31.464');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('2943a9d6-897b-4fa3-9591-b8fd5175fda4', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年排名前十的设计师签单金额', 'SELECT TOP 10\n    ci.Designer AS 设计师,\n    COUNT(tc.[20htje]) AS 签单个数,\n    SUM(tc.[20htje]) AS 签单金额\nFROM Form_Custom_TK0022 tc\nLEFT JOIN Crm_IntentCustomer ci ON tc.IntentCustomerId = ci.IntentCustomerId\nWHERE YEAR(tc.[20htrq]) = 2026\nGROUP BY ci.Designer\nORDER BY 3 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:34:25.089');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('3057e767-0bcf-480b-b536-ca53cf4a674f', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    c.DesignerDeptName AS 设计部门,\n    c.DesignerDeptCode AS 部门编码,\n    COUNT(DISTINCT c.IntentCustomerId) AS 总客户数,\n    COUNT(DISTINCT CASE WHEN tk.IntentCustomerId IS NOT NULL THEN c.IntentCustomerId END) AS 签单客户数,\n    CAST(COUNT(DISTINCT CASE WHEN tk.IntentCustomerId IS NOT NULL THEN c.IntentCustomerId END) AS DECIMAL(10,4)) * 100 / \n    NULLIF(COUNT(DISTINCT c.IntentCustomerId), 0) AS 签单率\nFROM Crm_IntentCustomer c\nLEFT JOIN Form_Custom_TK0022 tk ON c.IntentCustomerId = tk.IntentCustomerId \n    AND YEAR(tk.[20htrq]) = 2025\nWHERE c.DesignerDeptName IS NOT NULL\nGROUP BY c.DesignerDeptName, c.DesignerDeptCode\nORDER BY 签单率 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 02:53:31.502');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('305969e5-9960-4d8d-a948-7ab4d1c2c701', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单金额排名', 'SELECT \n    cic.DesignerDeptName AS 设计部门,\n    cic.DesignerDeptCode AS 部门编码,\n    COUNT(tk.[20htbh]) AS [20合同个数],\n    SUM(tk.[20htje]) AS [20合同总金额]\nFROM Form_Custom_TK0022 tk\nINNER JOIN Crm_IntentCustomer cic \n    ON tk.IntentCustomerId = cic.IntentCustomerId\nWHERE tk.[20htrq] >= \'2025-01-01\' \n    AND tk.[20htrq] < \'2026-01-01\'\nGROUP BY cic.DesignerDeptName, cic.DesignerDeptCode\nORDER BY [20合同总金额] DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:02:14.841');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('311d3fbd-830a-4f61-a41d-dfb94a3c4169', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询客户分布', '', '', 1, '2026-03-20 15:22:37.836');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('31e1a2ed-f2e7-4520-8507-2433b8e42049', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    c.DesignerDeptName AS 设计部门,\n    COUNT(DISTINCT c.IntentCustomerId) AS 客户总数,\n    COUNT(DISTINCT t.IntentCustomerId) AS 签约客户数,\n    CAST(COUNT(DISTINCT t.IntentCustomerId) AS DECIMAL(10,4)) / NULLIF(COUNT(DISTINCT c.IntentCustomerId), 0) AS 签单率\nFROM Crm_IntentCustomer c\nLEFT JOIN Form_Custom_TK0022 t ON c.IntentCustomerId = t.IntentCustomerId\nWHERE c.CreateDate >= \'2025-01-01\' \n    AND c.CreateDate < \'2026-01-01\'\n    AND c.DesignerDeptName IS NOT NULL\nGROUP BY c.DesignerDeptName\nORDER BY 签单率 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:00:37.709');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('39b847b2-69ec-4bb0-a68c-78e115fb28f7', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年排名前十的设计师签单金额', 'SELECT TOP 10\n    c.Designer AS 设计师,\n    COUNT(tk.[20htbh]) AS 签单个数,\n    SUM(tk.[20htje]) AS 签单金额\nFROM Form_Custom_TK0022 tk\nLEFT JOIN Crm_IntentCustomer c ON tk.IntentCustomerId = c.IntentCustomerId\nWHERE YEAR(tk.[20htrq]) = 2026\nGROUP BY c.Designer\nORDER BY 签单金额 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:14:53.749');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('3c3e74a2-be0b-4a03-a1bf-05e7033e7b37', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    ic.DesignerDeptName AS 设计部门,\n    COUNT(DISTINCT ic.IntentCustomerId) AS 客户总数,\n    COUNT(DISTINCT CASE WHEN tk.IntentCustomerId IS NOT NULL THEN ic.IntentCustomerId END) AS 签单客户数,\n    CAST(COUNT(DISTINCT CASE WHEN tk.IntentCustomerId IS NOT NULL THEN ic.IntentCustomerId END) AS numeric(10,4)) / \n        CAST(COUNT(DISTINCT ic.IntentCustomerId) AS numeric(10,4)) AS 签单率\nFROM Crm_IntentCustomer ic\nLEFT JOIN Form_Custom_TK0022 tk \n    ON ic.IntentCustomerId = tk.IntentCustomerId\nWHERE ic.IsFormDead = 0\n    AND ic.DesignerDeptName IS NOT NULL\n    AND DATEPART(YEAR, tk.[20htrq]) = 2025\nGROUP BY ic.DesignerDeptName\nORDER BY 4 DESC', '客户信息,20合同', 1, '2026-03-21 08:07:53.511');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('3d33f5b9-7f8b-4462-b10e-62c01301e5a1', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    ci.DesignerDeptName AS 设计部门,\n    COUNT(DISTINCT ci.IntentCustomerId) AS 客户总数,\n    COUNT(DISTINCT tk.IntentCustomerId) AS 签单客户数,\n    CAST(COUNT(DISTINCT tk.IntentCustomerId) * 1.0 / NULLIF(COUNT(DISTINCT ci.IntentCustomerId), 0) AS DECIMAL(10,4)) AS 签单率\nFROM Crm_IntentCustomer ci\nLEFT JOIN Form_Custom_TK0022 tk ON ci.IntentCustomerId = tk.IntentCustomerId\nWHERE ci.CreateDate >= \'2025-01-01\' \n    AND ci.CreateDate < \'2026-01-01\'\n    AND ci.DesignerDeptName IS NOT NULL\nGROUP BY ci.DesignerDeptName\nORDER BY 签单率 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 02:55:17.898');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('3e6130aa-f37e-4868-9205-61fca36f15e7', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    ic.DesignerDeptName AS 设计部门,\n    COUNT(DISTINCT ic.IntentCustomerId) AS 客户总数,\n    COUNT(DISTINCT tk.IntentCustomerId) AS 签单客户数,\n    COUNT(tk.[20htbh]) AS 签单合同数,\n    SUM(ISNULL(tk.[20htje], 0)) AS 签单总金额,\n    CAST(COUNT(DISTINCT tk.IntentCustomerId) AS DECIMAL(18,2)) / \n        NULLIF(COUNT(DISTINCT ic.IntentCustomerId), 0) * 100 AS 签单率\nFROM Crm_IntentCustomer ic\nLEFT JOIN Form_Custom_TK0022 tk \n    ON ic.IntentCustomerId = tk.IntentCustomerId \n    AND tk.[20htrq] >= \'2025-01-01\' \n    AND tk.[20htrq] < \'2026-01-01\'\nWHERE ic.IsFormDead = 0\n    AND ic.DesignerDeptName IS NOT NULL\n    AND ic.DesignerDeptName <> \'\'\nGROUP BY ic.DesignerDeptName\nORDER BY 签单率 DESC', '客户信息,20合同', 1, '2026-03-21 08:02:40.829');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('427e077c-8df0-4555-88dd-c176a1f71b1a', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部签单情况', 'SELECT \n    c.DesignerDeptName AS 设计部门,\n    c.DesignerDeptCode AS 设计部门编码,\n    COUNT(tk.[20htbh]) AS 签单数量,\n    SUM(tk.[20htje]) AS 签单总金额\nFROM Crm_IntentCustomer c\nINNER JOIN Form_Custom_TK0022 tk ON c.IntentCustomerId = tk.IntentCustomerId\nWHERE c.IsFormDead = 0\n    AND tk.[20htrq] >= \'2025-01-01\' \n    AND tk.[20htrq] < \'2026-01-01\'\nGROUP BY c.DesignerDeptName, c.DesignerDeptCode\nORDER BY SUM(tk.[20htje]) DESC', '客户信息,20合同', 1, '2026-03-21 03:20:28.567');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('4ef061cc-d6de-472c-a116-7c750831dd4c', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '绑定列名\nCreateUserName', 'SELECT \n    crm.IntentCustomerId,\n    crm.CustomerName,\n    crm.CustomerNo,\n    tk.CreateUserName\nFROM Crm_IntentCustomer AS crm\nLEFT JOIN Form_Custom_TK0022 AS tk ON crm.IntentCustomerId = tk.IntentCustomerId\nWHERE crm.isFormDead = 0', '客户信息,20合同', 1, '2026-03-21 04:57:13.020');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('54212520-c29f-4681-9f62-abd42964a35c', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    ic.DesignerDeptName AS DesignDept,\n    COUNT(*) AS TotalCustomers,\n    SUM(IIF(c.[20htbh] IS NOT NULL, 1, 0)) AS SignedCustomers,\n    CAST(CAST(ROUND(SUM(IIF(c.[20htbh] IS NOT NULL, 1, 0)) * 100.0 / NULLIF(COUNT(*), 0), 2) AS DECIMAL(10,2)) AS NVARCHAR) + \'%\' AS SignRate\nFROM Crm_IntentCustomer ic\nLEFT JOIN Form_Custom_TK0022 c ON ic.IntentCustomerId = c.IntentCustomerId\nWHERE ic.IsFormDead = 0 \n    AND YEAR(ic.CreateDate) = 2025\n    AND ic.DesignerDeptName IS NOT NULL\n    AND ic.DesignerDeptName <> \'\'\nGROUP BY ic.DesignerDeptName\nORDER BY 4 DESC', '客户信息,20合同', 1, '2026-03-21 06:48:15.131');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('5e1ef6f5-c38f-448f-b0f4-47e0d82ade39', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年设计部门签单金额排名，按设计部门统计', 'SELECT \n    cic.DesignerDeptName AS 设计部门,\n    COUNT(*) AS 合同个数,\n    SUM(fct.[20htje]) AS 签单总金额\nFROM Form_Custom_TK0022 fct\nLEFT JOIN Crm_IntentCustomer cic ON fct.IntentCustomerId = cic.IntentCustomerId\nWHERE fct.[20htrq] >= \'2026-01-01\' \n  AND fct.[20htrq] < \'2027-01-01\'\n  AND cic.DesignerDeptName IS NOT NULL\nGROUP BY cic.DesignerDeptName\nORDER BY SUM(fct.[20htje]) DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:05:17.077');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('6254492c-03ad-445a-b94a-b388fd860323', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    c.DesignDeepDeptName AS 设计部门,\n    COUNT(DISTINCT c.IntentCustomerId) AS 客户总数,\n    COUNT(DISTINCT CASE WHEN t.IntentCustomerId IS NOT NULL THEN c.IntentCustomerId END) AS 签单客户数,\n    CAST(COUNT(DISTINCT CASE WHEN t.IntentCustomerId IS NOT NULL THEN c.IntentCustomerId END) AS DECIMAL(10,2)) / \n        NULLIF(COUNT(DISTINCT c.IntentCustomerId), 0) AS 签单率,\n    COUNT(DISTINCT t.[20htbh]) AS 合同个数,\n    ISNULL(SUM(t.[20htje]), 0) AS 合同总金额\nFROM Crm_IntentCustomer c\nLEFT JOIN Form_Custom_TK0022 t ON c.IntentCustomerId = t.IntentCustomerId \n    AND YEAR(t.CreateDate) = 2025\nWHERE c.IsFormDead = 0\n    AND YEAR(c.CreateDate) = 2025\nGROUP BY c.DesignDeepDeptName\nHAVING COUNT(DISTINCT c.IntentCustomerId) > 0\nORDER BY 签单率 DESC', '客户信息,20合同', 1, '2026-03-21 08:16:35.529');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('64ca7b73-d069-4c2e-b7c3-ec5d8913ffc3', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    DesignDeepDeptName AS 设计部门,\n    COUNT(*) AS 客户总数,\n    SUM(CASE WHEN IsSuccessfulCase = 1 THEN 1 ELSE 0 END) AS 签单客户数,\n    CAST(SUM(CASE WHEN IsSuccessfulCase = 1 THEN 1 ELSE 0 END) AS FLOAT) / COUNT(*) AS 签单率\nFROM Crm_IntentCustomer\nWHERE isFormDead = 0\n    AND YEAR(CreateDate) = 2025\n    AND DesignDeepDeptName IS NOT NULL\n    AND DesignDeepDeptName <> \'\'\nGROUP BY DesignDeepDeptName\nORDER BY 签单率 DESC', '客户信息', 1, '2026-03-21 06:49:27.777');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('754205cb-980e-4f42-a199-5b98592b0a92', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    MAX(crm.DesignerDeptName) AS DesignDeptName,\n    SUM(CASE WHEN tk.IntentCustomerId IS NOT NULL THEN 1 ELSE 0 END) AS SignCustomerCount,\n    COUNT(DISTINCT crm.IntentCustomerId) AS TotalCustomerCount,\n    CAST(SUM(CASE WHEN tk.IntentCustomerId IS NOT NULL THEN 1 ELSE 0 END) AS DECIMAL(10,2)) / \n        NULLIF(COUNT(DISTINCT crm.IntentCustomerId), 0) AS SignRate\nFROM Crm_IntentCustomer crm\nLEFT JOIN Form_Custom_TK0022 tk ON crm.IntentCustomerId = tk.IntentCustomerId\nWHERE crm.IsFormDead = 0\n    AND YEAR(tk.CreateDate) = 2025\nGROUP BY crm.DesignerDeptCode\nORDER BY SignRate DESC', '客户信息,20合同', 1, '2026-03-21 08:09:14.827');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('9f70a34f-bf0b-41c8-86a8-975117f398e9', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年签订的20合同，转化50合同的周期分布', 'SELECT \n    CASE \n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 7 THEN \'7天内\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 14 THEN \'7-14天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 30 THEN \'14-30天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 60 THEN \'30-60天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 90 THEN \'60-90天\'\n        ELSE \'90天以上\'\n    END AS 周期分布,\n    COUNT(*) AS 合同数量\nFROM Form_Custom_TK0022 tk\nLEFT JOIN Crm_FormConstructionContract ccc \n    ON tk.IntentCustomerId = ccc.IntentCustomerId\nWHERE YEAR(tk.[20htrq]) = 2025\nGROUP BY \n    CASE \n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 7 THEN \'7天内\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 14 THEN \'7-14天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 30 THEN \'14-30天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 60 THEN \'30-60天\'\n        WHEN DATEDIFF(DAY, tk.[20htrq], ccc.CreateDate) <= 90 THEN \'60-90天\'\n        ELSE \'90天以上\'\n    END\nORDER BY 周期分布', '20合同,50合同/施工合同', 1, '2026-03-21 03:39:44.050');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('a4f8ca23-7d7a-4e15-aa22-047ec568ee76', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年设计部门签单率排名', 'SELECT \n    dfc.FurnitureDesignerDeptName AS 设计部门,\n    COUNT(DISTINCT dfc.DraftCustomerId) AS 总客户数,\n    COUNT(DISTINCT tc.IntentCustomerId) AS 签单客户数,\n    CAST(COUNT(DISTINCT tc.IntentCustomerId) AS FLOAT) / COUNT(DISTINCT dfc.DraftCustomerId) AS 签单率\nFROM Crm_DraftCustomer dfc\nLEFT JOIN Form_Custom_TK0022 tc ON dfc.DraftCustomerId = tc.IntentCustomerId\nWHERE (tc.[20htrq] >= \'2025-01-01\' AND tc.[20htrq] < \'2026-01-01\')\n   OR tc.IntentCustomerId IS NULL\n   OR tc.[20htrq] IS NULL\nGROUP BY dfc.FurnitureDesignerDeptName\nHAVING COUNT(DISTINCT dfc.DraftCustomerId) > 0\nORDER BY 签单率 DESC', '公海池客,20合同/设计合同', 1, '2026-03-22 02:45:38.694');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('c8daba8b-6b18-4e8c-b10e-b1d0ca4490b9', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询所有客户', 'SELECT * FROM Crm_IntentCustomer WHERE isFormDead = 0', '客户信息', 1, '2026-03-20 16:01:23.938');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('ccfc6e23-9181-4e28-8a03-7add8549e072', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2025年签单规则', '', '', 1, '2026-03-20 15:20:28.778');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('d1949b46-5525-483b-adb3-b320584e6f0f', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年排名前十的设计师签单金额', 'SELECT TOP 10\n    c.Designer AS 设计师,\n    COUNT(tk.[20htbh]) AS 签单个数,\n    SUM(tk.[20htje]) AS 签单金额\nFROM Form_Custom_TK0022 tk\nINNER JOIN Crm_IntentCustomer c ON tk.IntentCustomerId = c.IntentCustomerId\nWHERE YEAR(tk.[20htrq]) = 2026\nGROUP BY c.Designer\nORDER BY 签单金额 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:43:25.207');
INSERT INTO `query_history` (`id`, `userId`, `query`, `sql`, `tables`, `status`, `createdAt`) VALUES ('fe0c2487-421f-457c-ac3a-ee5d80a78cd9', 'a5b7d687-3f84-48b5-94b6-d38266e11153', '查询2026年设计部门签单金额排名', 'SELECT \n    cic.Designer AS 设计师,\n    cic.DesignerDeptName AS 设计部门,\n    COUNT(*) AS 合同个数,\n    SUM(fct.[20htje]) AS 签单金额\nFROM Form_Custom_TK0022 fct\nINNER JOIN Crm_IntentCustomer cic ON fct.IntentCustomerId = cic.IntentCustomerId\nWHERE YEAR(fct.[20htrq]) = 2026\nGROUP BY cic.Designer, cic.DesignerDeptName\nORDER BY 签单金额 DESC', '20合同/设计合同,客户信息', 1, '2026-03-22 03:03:59.987');
